const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// In-memory data stores (replace with database in production)
const users = new Map();
const levelCompletions = new Map();
const rewards = new Map();
const claimedRewards = new Map();

// Reward tiers configuration
const REWARD_TIERS = {
  bronze: { minScore: 0, maxScore: 499, coins: 10, gems: 0, stars: 1 },
  silver: { minScore: 500, maxScore: 999, coins: 25, gems: 1, stars: 2 },
  gold: { minScore: 1000, maxScore: 1999, coins: 50, gems: 3, stars: 3 },
  platinum: { minScore: 2000, maxScore: Infinity, coins: 100, gems: 5, stars: 3 }
};

// Time bonus thresholds (seconds)
const TIME_BONUSES = [
  { maxTime: 30, bonusCoins: 50, bonusGems: 2 },
  { maxTime: 60, bonusCoins: 25, bonusGems: 1 },
  { maxTime: 120, bonusCoins: 10, bonusGems: 0 },
  { maxTime: Infinity, bonusCoins: 0, bonusGems: 0 }
];

// Level configuration
const LEVELS = {};
for (let i = 1; i <= 100; i++) {
  LEVELS[i] = {
    id: i,
    name: `Level ${i}`,
    maxScore: 3000 + i * 100,
    maxTimeAllowed: 300, // 5 minutes max
    minScoreToPass: 100 + i * 10,
    unlockRequirement: i === 1 ? null : i - 1
  };
}

// Middleware: Simple auth via user-id header
function authenticate(req, res, next) {
  const userId = req.headers['x-user-id'];
  if (!userId) {
    return res.status(401).json({ error: 'Missing x-user-id header' });
  }

  if (!users.has(userId)) {
    // Auto-create user for simplicity
    users.set(userId, {
      id: userId,
      coins: 0,
      gems: 0,
      totalStars: 0,
      completedLevels: {},
      createdAt: new Date().toISOString()
    });
    levelCompletions.set(userId, []);
    claimedRewards.set(userId, new Set());
  }

  req.userId = userId;
  req.user = users.get(userId);
  next();
}

// Validation middleware for level completion
function validateLevelCompletion(req, res, next) {
  const { levelId, score, timeSeconds, moves } = req.body;

  if (levelId === undefined || score === undefined || timeSeconds === undefined) {
    return res.status(400).json({
      error: 'Missing required fields: levelId, score, timeSeconds'
    });
  }

  if (!Number.isInteger(levelId) || levelId < 1 || levelId > 100) {
    return res.status(400).json({ error: 'Invalid levelId. Must be between 1 and 100.' });
  }

  if (typeof score !== 'number' || score < 0) {
    return res.status(400).json({ error: 'Invalid score. Must be a non-negative number.' });
  }

  if (typeof timeSeconds !== 'number' || timeSeconds < 0) {
    return res.status(400).json({ error: 'Invalid timeSeconds. Must be a non-negative number.' });
  }

  if (moves !== undefined && (!Number.isInteger(moves) || moves < 0)) {
    return res.status(400).json({ error: 'Invalid moves. Must be a non-negative integer.' });
  }

  const level = LEVELS[levelId];

  // Check if score exceeds maximum possible for the level
  if (score > level.maxScore) {
    return res.status(400).json({
      error: `Score ${score} exceeds maximum possible score ${level.maxScore} for level ${levelId}`
    });
  }

  // Check if time exceeds maximum allowed
  if (timeSeconds > level.maxTimeAllowed) {
    return res.status(400).json({
      error: `Time ${timeSeconds}s exceeds maximum allowed time ${level.maxTimeAllowed}s for level ${levelId}`
    });
  }

  // Sanity check: unrealistically fast completion
  if (timeSeconds < 1) {
    return res.status(400).json({ error: 'Completion time is unrealistically fast.' });
  }

  next();
}

// Helper: Determine reward tier based on score
function getRewardTier(score) {
  for (const [tierName, tier] of Object.entries(REWARD_TIERS)) {
    if (score >= tier.minScore && score <= tier.maxScore) {
      return { tierName, ...tier };
    }
  }
  return { tierName: 'bronze', ...REWARD_TIERS.bronze };
}

// Helper: Calculate time bonus
function getTimeBonus(timeSeconds) {
  for (const bonus of TIME_BONUSES) {
    if (timeSeconds <= bonus.maxTime) {
      return bonus;
    }
  }
  return { bonusCoins: 0, bonusGems: 0 };
}

// Helper: Generate reward ID
function generateRewardId() {
  return crypto.randomUUID();
}

// ==================== ENDPOINTS ====================

// POST /api/levels/complete - Complete a level
app.post('/api/levels/complete', authenticate, validateLevelCompletion, (req, res) => {
  const { levelId, score, timeSeconds, moves } = req.body;
  const user = req.user;
  const level = LEVELS[levelId];

  // Check unlock requirement
  if (level.unlockRequirement && !user.completedLevels[level.unlockRequirement]) {
    return res.status(403).json({
      error: `Level ${levelId} is locked. Complete level ${level.unlockRequirement} first.`
    });
  }

  // Check minimum score to pass
  if (score < level.minScoreToPass) {
    return res.status(200).json({
      success: false,
      passed: false,
      message: `Score ${score} is below the minimum passing score of ${level.minScoreToPass}`,
      levelId,
      score,
      timeSeconds,
      minScoreRequired: level.minScoreToPass
    });
  }

  // Calculate rewards
  const rewardTier = getRewardTier(score);
  const timeBonus = getTimeBonus(timeSeconds);

  const totalCoins = rewardTier.coins + timeBonus.bonusCoins;
  const totalGems = rewardTier.gems + timeBonus.bonusGems;
  const stars = rewardTier.stars;

  // Check if this is a new best score for this level
  const previousBest = user.completedLevels[levelId];
  const isNewBest = !previousBest || score > previousBest.bestScore;
  const isFirstCompletion = !previousBest;

  // Create completion record
  const completionId = generateRewardId();
  const completion = {
    id: completionId,
    userId: req.userId,
    levelId,
    score,
    timeSeconds,
    moves: moves || null,
    tier: rewardTier.tierName,
    stars,
    isNewBest,
    isFirstCompletion,
    completedAt: new Date().toISOString()
  };

  // Store completion
  const userCompletions = levelCompletions.get(req.userId);
  userCompletions.push(completion);

  // Update user's level data
  if (isNewBest) {
    user.completedLevels[levelId] = {
      bestScore: score,
      bestTime: previousBest ? Math.min(previousBest.bestTime, timeSeconds) : timeSeconds,
      stars: previousBest ? Math.max(previousBest.stars, stars) : stars,
      completionCount: previousBest ? previousBest.completionCount + 1 : 1,
      firstCompletedAt: previousBest ? previousBest.firstCompletedAt : new Date().toISOString(),
      lastCompletedAt: new Date().toISOString()
    };
  } else {
    user.completedLevels[levelId].completionCount += 1;
    user.completedLevels[levelId].lastCompletedAt = new Date().toISOString();
    if (timeSeconds < user.completedLevels[levelId].bestTime) {
      user.completedLevels[levelId].bestTime = timeSeconds;
    }
  }

  // Recalculate total stars
  user.totalStars = Object.values(user.completedLevels).reduce((sum, l) => sum + l.stars, 0);

  // Create pending reward
  const rewardId = generateRewardId();
  const reward = {
    id: rewardId,
    userId: req.userId,
    completionId,
    levelId,
    tier: rewardTier.tierName,
    coins: totalCoins,
    gems: totalGems,
    stars,
    timeBonus: {
      bonusCoins: timeBonus.bonusCoins,
      bonusGems: timeBonus.bonusGems
    },
    claimed: false,
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString() // 24h expiry
  };

  rewards.set(rewardId, reward);

  res.status(200).json({
    success: true,
    passed: true,
    completion: {
      id: completionId,
      levelId,
      score,
      timeSeconds,
      moves: moves || null,
      tier: rewardTier.tierName,
      stars,
      isNewBest,
      isFirstCompletion
    },
    reward: {
      id: rewardId,
      coins: totalCoins,
      gems: totalGems,
      stars,
      tier: rewardTier.tierName,
      timeBonus: {
        bonusCoins: timeBonus.bonusCoins,
        bonusGems: timeBonus.bonusGems
      },
      claimed: false,
      expiresAt: reward.expiresAt
    },
    user: {
      totalCoins: user.coins,
      totalGems: user.gems,
      totalStars: user.totalStars
    }
  });
});

// POST /api/rewards/:rewardId/claim - Claim a specific reward
app.post('/api/rewards/:rewardId/claim', authenticate, (req, res) => {
  const { rewardId } = req.params;
  const user = req.user;

  const reward = rewards.get(rewardId);

  if (!reward) {
    return res.status(404).json({ error: 'Reward not found.' });
  }

  if (reward.userId !== req.userId) {
    return res.status(403).json({ error: 'This reward does not belong to you.' });
  }

  if (reward.claimed) {
    return res.status(409).json({ error: 'Reward has already been claimed.' });
  }

  // Check expiry
  if (new Date(reward.expiresAt) < new Date()) {
    return res.status(410).json({ error: 'Reward has expired and can no longer be claimed.' });
  }

  // Award the reward
  user.coins += reward.coins;
  user.gems += reward.gems;

  // Mark as claimed
  reward.claimed = true;
  reward.claimedAt = new Date().toISOString();

  const userClaimed = claimedRewards.get(req.userId);
  userClaimed.add(rewardId);

  res.status(200).json({
    success: true,
    claimed: {
      rewardId: reward.id,
      levelId: reward.levelId,
      coins: reward.coins,
      gems: reward.gems,
      stars: reward.stars,
      tier: reward.tier,
      claimedAt: reward.claimedAt
    },
    user: {
      totalCoins: user.coins,
      totalGems: user.gems,
      totalStars: user.totalStars
    }
  });
});

// POST /api/rewards/claim-all - Claim all pending rewards
app.post('/api/rewards/claim-all', authenticate, (req, res) => {
  const user = req.user;
  const now = new Date();

  let totalCoinsAwarded = 0;
  let totalGemsAwarded = 0;
  const claimedList = [];

  for (const [rewardId, reward] of rewards.entries()) {
    if (reward.userId !== req.userId) continue;
    if (reward.claimed) continue;
    if (new Date(reward.expiresAt) < now) continue;

    user.coins += reward.coins;
    user.gems += reward.gems;
    totalCoinsAwarded += reward.coins;
    totalGemsAwarded += reward.gems;

    reward.claimed = true;
    reward.claimedAt = now.toISOString();

    const userClaimed = claimedRewards.get(req.userId);
    userClaimed.add(rewardId);

    claimedList.push({
      rewardId: reward.id,
      levelId: reward.levelId,
      coins: reward.coins,
      gems: reward.gems,
      tier: reward.tier
    });
  }

  res.status(200).json({
    success: true,
    claimedCount: claimedList.length,
    totalCoinsAwarded,
    totalGemsAwarded,
    claimed: claimedList,
    user: {
      totalCoins: user.coins,
      totalGems: user.gems,
      totalStars: user.totalStars
    }
  });
});

// GET /api/rewards/pending - Get all pending (unclaimed) rewards
app.get('/api/rewards/pending', authenticate, (req, res) => {
  const now = new Date();
  const pending = [];

  for (const [, reward] of rewards.entries()) {
    if (reward.userId !== req.userId) continue;
    if (reward.claimed) continue;

    const expired = new Date(reward.expiresAt) < now;
    pending.push({
      id: reward.id,
      levelId: reward.levelId,
      coins: reward.coins,
      gems: reward.gems,
      stars: reward.stars,
      tier: reward.tier,
      timeBonus: reward.timeBonus,
      expired,
      expiresAt: reward.expiresAt,
      createdAt: reward.createdAt
    });
  }

  res.status(200).json({
    success: true,
    count: pending.length,
    rewards: pending
  });
});

